const data = items[0].json.body;
let errors = [];

if (!data.partner_id) errors.push("partner_id missing");
if (!data.partner_name) errors.push("partner_name missing");
if (data.quota === undefined || data.quota === null) errors.push("quota missing");
if (data.consumed === undefined || data.consumed === null) errors.push("consumed missing");

// Numeric validation
if (data.quota !== undefined && isNaN(Number(data.quota))) {
  errors.push("quota not a number");
}
if (data.consumed !== undefined && isNaN(Number(data.consumed))) {
  errors.push("consumed not a number");
}

// If any validation failed — go to fallback
if (errors.length > 0) {
  return [
    {
      json: {
        status: "invalid",
        errors,
        ...data
      }
    }
  ];
}

// If everything is valid
return [
  {
    json: {
      status: "valid",
      ...data
    }
  }
];

const item = items[0].json;

const quota = Number(item.quota);
const consumed = Number(item.consumed);

if (!quota || isNaN(quota) || isNaN(consumed)) {
  // invalid numeric values → fallback
  return [
    {
      json: {
        action: "invalid_usage",
        ...item
      }
    }
  ];
}

// Calculate usage %
const usage_pct = Math.round((consumed / quota) * 100 * 100) / 100; // 2 decimals

// If below 80% → stop workflow
if (usage_pct < 80) {
  return [
    {
      json: {
        action: "no_alert",
        usage_pct,
        ...item
      }
    }
  ];
}

// If >= 80 → proceed to next step (dedupe check)
return [
  {
    json: {
      action: "proceed",
      usage_pct,
      ...item
    }
  }
];

